arguments.argument:
//if the character is standing on the switch
if global.gamePaused=false
{
  if isCollisionCharacterTop(1,0)
  {
    if y<baseY+16 {yVel=0.5}
    else {yVel=0}
    standTime=30
  }
  else
  {
    standTime-=1
    if standTime<=0
    {
      if y>baseY {yVel=-0.5}
      else {yVel=0}
    }
    else {yVel=0}
  }
}
